# MAGIC %md
# MAGIC # Load Synthetic Data into L2.2 Unified Model
# MAGIC Loads pre-generated synthetic CSV data directly into L2.2 dimension and fact tables.
# MAGIC The CSVs are generated by `scripts/generate_synthetic_data.py` and contain ~294K rows
# MAGIC with columns matching the L2.2 DDL schema exactly.
# MAGIC
# MAGIC **Tables loaded:**
# MAGIC - `dim_product` (500), `dim_material` (600), `dim_test_method` (400)
# MAGIC - `dim_site` (50), `dim_market` (30)
# MAGIC - `dim_specification` (2,000), `dim_specification_item` (16,000)
# MAGIC - `dim_batch` (5,000), `dim_instrument` (200), `dim_laboratory` (80)
# MAGIC - `fact_specification_limit` (120,000), `fact_analytical_result` (150,000)

# COMMAND ----------

# MAGIC %md
# MAGIC ## Resolve CSV Path

# COMMAND ----------

import os

# In Databricks Repos, notebook path is under /Workspace/Repos/...
# The synthetic_data/ directory is at the repo root, two levels up from this notebook.
notebook_path = dbutils.notebook.entry_point.getDbutils().notebook().getContext().notebookPath().get()
repo_root = os.path.dirname(os.path.dirname(notebook_path))
csv_dir = f"/Workspace{repo_root}/synthetic_data"

# Fallback: if running locally or CSVs are in DBFS
if not os.path.exists(csv_dir):
    csv_dir = "/Workspace/synthetic_data"
if not os.path.exists(csv_dir):
    csv_dir = "file:/home/user/pharma-quality/synthetic_data"

print(f"CSV directory: {csv_dir}")

# COMMAND ----------

# MAGIC %md
