# COMMAND ----------

# MAGIC %md
# MAGIC ## Load CSVs into L2.2 Tables

# COMMAND ----------

results = []

for tbl in TABLES:
    csv_path = f"{csv_dir}/{tbl['csv']}"
    table_name = tbl["table"]

    df = (
        spark.read
        .option("header", "true")
        .option("nullValue", "")
        .option("timestampFormat", "yyyy-MM-dd'T'HH:mm:ss.SSSSSS")
        .schema(tbl["schema"])
        .csv(csv_path)
    )

    row_count = df.count()
    df.write.format("delta").mode("append").saveAsTable(table_name)
    results.append((tbl["csv"], table_name.split(".")[-1], row_count))
    print(f"  Loaded {row_count:>8,} rows into {table_name}")

print("\nSynthetic data loading complete.")

